```aiken
use aiken/builtin
use aiken/crypto.{blake2b_224}
use aiken/primitive/bytearray

/// Prepends the version byte and appends the blake2b_224 hash of `param`
/// to `prefix`, producing the running prefix after the first parameter.
fn append_first_param_to_prefix(
  version: Int,
  prefix: ByteArray,
  param: ByteArray,
) -> ByteArray {
  builtin.integer_to_bytearray(True, 1, version)
    |> bytearray.concat(prefix)
    |> bytearray.concat(blake2b_224(param))
}
```

**How it works:**
1. `builtin.integer_to_bytearray(True, 1, version)` encodes `version` as a 1-byte big-endian ByteArray.
2. That byte is concatenated with `prefix` (the static CBOR bytes before the first parameter slot).
3. Finally, `blake2b_224(param)` — always 28 bytes — is appended, so the total length grows by a fixed amount regardless of the actual parameter value.

```aiken
use aiken/builtin
use aiken/collection/list
use aiken/primitive/bytearray

const postfix: ByteArray = #"0001"

/// Construye el ByteArray del script aplicando una lista de parámetros
/// ya pre-hasheados sobre el `prefix` dado.
/// El resultado puede pasarse a `blake2b_224` para obtener el ScriptHash.
fn build_script_bytes(
  version: Int,
  prefix: ByteArray,
  prehashed_params: List<ByteArray>,
) -> ByteArray {
  let version_byte = builtin.integer_to_bytearray(True, 1, version)
  let base = version_byte |> bytearray.concat(prefix)
  let with_params =
    list.foldl(
      prehashed_params,
      base,
      fn(param, acc) { acc |> bytearray.concat(param) },
    )
  with_params |> bytearray.concat(postfix)
}
```

**Notas:**
- `builtin.integer_to_bytearray(True, 1, version)` codifica la versión en exactamente 1 byte big-endian.
- `list.foldl` acumula los parámetros pre-hasheados de izquierda a derecha sobre el prefijo base.
- Al final se añade `postfix` (`#"0001"`), que es la terminación fija del envelope CBOR.
- Si los parámetros **no** estuviesen pre-hasheados, habría que aplicarles `blake2b_224` antes de concatenarlos.

```aiken
use aiken/builtin
use aiken/collection/list
use aiken/crypto.{ScriptHash, blake2b_224}
use aiken/primitive/bytearray
use cardano/assets.{PolicyId}
use cardano/transaction.{Transaction}

const postfix: ByteArray = #"0001"

type MintRedeemer {
  wallet: ByteArray,
  prefix: ByteArray,
}

/// Derives the ScriptHash of a spending script instance parameterized by `wallet`.
fn derive_script_hash(
  version: Int,
  prefix: ByteArray,
  wallet: ByteArray,
) -> ScriptHash {
  let version_byte = builtin.integer_to_bytearray(True, 1, version)
  let script_bytes =
    version_byte
      |> bytearray.concat(prefix)
      |> bytearray.concat(blake2b_224(wallet))
      |> bytearray.concat(postfix)
  blake2b_224(script_bytes)
}

validator parameterized_mint {
  mint(redeemer: MintRedeemer, _policy_id: PolicyId, self: Transaction) -> Bool {
    let MintRedeemer { wallet, prefix } = redeemer
    let expected_hash = derive_script_hash(1, prefix, wallet)

    // At least one output must be locked at the derived script address.
    list.any(
      self.outputs,
      fn(output) {
        when output.address.payment_credential is {
          Script(script_hash) -> script_hash == expected_hash
          _ -> False
        }
      },
    )
  }
}
```

**How it works:**
1. The redeemer supplies the raw `wallet` bytes and the static `prefix` extracted from a dummy script instance.
2. `derive_script_hash` assembles `version_byte | prefix | blake2b_224(wallet) | postfix` and hashes the whole thing with `blake2b_224`, producing the 28-byte `ScriptHash` of the expected spending script instance.
3. The validator checks that at least one transaction output carries a `Script` payment credential matching that hash, ensuring minted tokens land at a valid parameterized address.

```aiken
use aiken/collection/list
use cardano/assets
use cardano/transaction.{Input, Output, OutputReference, Transaction}

pub type Redeemer {
  input_index: Int,
  output_index: Int,
}

fn one_to_one(
  input_index: Int,
  output_index: Int,
  own_ref: OutputReference,
  inputs: List<Input>,
  outputs: List<Output>,
  double_satisfaction_prevented: Bool,
  validation_logic: fn(Input, Output) -> Bool,
) -> Bool {
  expect double_satisfaction_prevented
  expect Some(Input { output_reference: in_ref, .. } as in_input) =
    inputs |> list.at(input_index)
  expect Some(out_utxo) = outputs |> list.at(output_index)
  expect own_ref == in_ref
  validation_logic(in_input, out_utxo)
}

validator lovelace_preserving {
  spend(
    _datum: Option<Data>,
    redeemer: Redeemer,
    own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    one_to_one(
      redeemer.input_index,
      redeemer.output_index,
      own_ref,
      self.inputs,
      self.outputs,
      True,
      fn(in_input, out_utxo) {
        let in_lovelace = assets.lovelace_of(in_input.output.value)
        let out_lovelace = assets.lovelace_of(out_utxo.value)
        out_lovelace >= in_lovelace
      },
    )
  }
}
```

```aiken
use aiken/collection/list
use aiken/crypto.{VerificationKeyHash}
use cardano/assets
use cardano/transaction.{Input, Output, OutputReference, Transaction}

pub type Datum {
  owner: VerificationKeyHash,
}

pub type Redeemer {
  input_index: Int,
  output_index: Int,
}

fn one_to_one(
  input_index: Int,
  output_index: Int,
  own_ref: OutputReference,
  inputs: List<Input>,
  outputs: List<Output>,
  double_satisfaction_prevented: Bool,
  validation_logic: fn(Input, Output) -> Bool,
) -> Bool {
  expect double_satisfaction_prevented
  expect Some(Input { output_reference: in_ref, .. } as in_input) =
    inputs |> list.at(input_index)
  expect Some(out_utxo) = outputs |> list.at(output_index)
  expect own_ref == in_ref
  validation_logic(in_input, out_utxo)
}

validator return_to_owner {
  spend(
    datum: Option<Datum>,
    redeemer: Redeemer,
    own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    expect Some(d) = datum
    one_to_one(
      redeemer.input_index,
      redeemer.output_index,
      own_ref,
      self.inputs,
      self.outputs,
      True,
      fn(_in_input, out_utxo) {
        list.has(self.extra_signatories, d.owner)
      },
    )
  }
}
```

Use `validate_withdraw` from `aiken_design_patterns/stake_validator`. The function takes the withdrawal script hash, the transaction redeemers, the index of the withdrawal redeemer in the redeemers list, and a validator function over the redeemer. Since you don't need to inspect the redeemer value, pass a function that always returns `True`:

```aiken
use aiken/crypto.{ScriptHash}
use aiken_design_patterns/stake_validator
use cardano/transaction.{Transaction}

validator my_spend_validator(withdraw_script_hash: ScriptHash) {
  spend(
    _datum: Option<Data>,
    _redeemer: Data,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    stake_validator.validate_withdraw(
      withdraw_script_hash,
      self.redeemers,
      0,
      fn(_redeemer) { True },
    )
  }
}
```

`validate_withdraw` internally calls `get_withdraw_scripts_redeemer_at` to locate the withdrawal redeemer at the given index and then applies your validator function to it. By passing `fn(_redeemer) { True }`, you only assert that the withdrawal script is present in the transaction.

```aiken
use aiken/crypto.{ScriptHash}
use aiken_design_patterns/stake_validator
use cardano/transaction.{OutputReference, Transaction}

validator guarded_spend(withdraw_script_hash: ScriptHash) {
  spend(
    _datum: Option<Data>,
    _redeemer: Data,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    stake_validator.validate_withdraw_with_amount(
      withdraw_script_hash,
      self.redeemers,
      0,
      self.withdrawals,
      0,
      fn(_redeemer, amount) { amount > 0 },
    )
  }
}
```

`validate_withdraw_with_amount` checks:
1. That the redeemer at index 0 has a `Withdraw(Script(withdraw_script_hash))` purpose.
2. That the withdrawal at index 0 belongs to the same `Script(withdraw_script_hash)` credential.
3. Calls your lambda with the redeemer and the withdrawn Lovelace amount — here asserting `amount > 0`.

```aiken
use aiken/crypto.{ScriptHash}
use aiken_design_patterns/stake_validator
use cardano/transaction.{OutputReference, Transaction}

pub type MyAction {
  DoSomething
  DoOther
}

validator delegated_spend(withdraw_script_hash: ScriptHash) {
  spend(
    _datum: Option<Data>,
    _redeemer: Data,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    stake_validator.validate_withdraw(
      withdraw_script_hash,
      self.redeemers,
      0,
      fn(raw_redeemer) {
        expect action: MyAction = raw_redeemer
        when action is {
          DoSomething -> True
          DoOther -> True
        }
      },
    )
  }

  else(_) {
    False
  }
}
```

El spend validator hace solo trabajo mínimo: delega toda la lógica real al script de retiro identificado por `withdraw_script_hash`. Dentro del lambda de validación, se usa `expect` para deserializar el redeemer crudo (`Data`) al tipo `MyAction` y se pueden manejar cada variante según la lógica de negocio requerida.

```aiken
use cardano/assets.{PolicyId}
use cardano/transaction.{OutputReference, Transaction}

validator tx_level_spend(mint_policy: PolicyId) {
  spend(
    _datum: Option<Data>,
    _redeemer: Data,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    !(self.mint |> assets.tokens(mint_policy) |> dict.is_empty)
  }

  else(_) {
    fail
  }
}
```

The `validate_mint_minimal` logic is inlined here: `assets.tokens(mint_policy)` extracts all tokens minted/burned under `mint_policy` from `self.mint`, and `dict.is_empty` checks whether the resulting dict is empty. The leading `!` asserts it is **not** empty, meaning the policy must fire in this transaction.

```aiken
use aiken/collection/dict
use aiken/collection/list
use cardano/assets.{AssetName, PolicyId}
use cardano/transaction.{Mint, OutputReference, Redeemer, ScriptPurpose, Transaction}

fn my_mint_validator(redeemer: Redeemer, tokens: dict.Dict<AssetName, Int>) -> Bool {
  expect rdmr: ByteArray = redeemer
  rdmr == "authorized" && dict.size(tokens) == 1
}

validator coupled_spend(mint_policy: PolicyId, redeemer_index: Int) {
  spend(
    _datum: Option<Data>,
    _redeemer: Data,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    let mint_purpose = Mint(mint_policy)
    expect Some(rdmr_pair) = self.redeemers |> list.at(redeemer_index)
    expect rdmr_pair.1st == mint_purpose
    let tokens = self.mint |> assets.tokens(mint_policy)
    my_mint_validator(rdmr_pair.2nd, tokens)
  }

  else(_) {
    fail
  }
}
```

This mirrors the `validate_mint` helper: it looks up the redeemer at the given positional index, confirms its `ScriptPurpose` matches `Mint(mint_policy)`, extracts minted tokens for the policy, then delegates to the custom validation function.

```aiken
use aiken/collection/list
use aiken/crypto.{VerificationKeyHash}
use cardano/assets.{PolicyId}
use cardano/transaction.{OutputReference, Transaction}

validator nft_with_owner(owner_pkh: VerificationKeyHash) {
  spend(
    _datum: Option<Data>,
    _redeemer: Data,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    let policy_id: PolicyId = own_policy_id()
    !(self.mint |> assets.tokens(policy_id) |> dict.is_empty)
  }

  mint(_redeemer: Data, _policy_id: PolicyId, self: Transaction) -> Bool {
