    tx: Transaction,
  ) {
    let Transaction { inputs, outputs, .. } = tx

    singular_utxo_indexer.one_to_many(
      input_output_validator: fn(_input: Input, _output_index: Int, output: Output) {
        assets.lovelace_of(output.value) >= 2_000_000
      },
      input_collective_outputs_validator: fn(_input: Input, outs: List<Output>) {
        list.length(outs) >= 1
      },
      input_index: redeemer.1st,
      output_indices: redeemer.2nd,
      own_ref: own_ref,
      inputs: inputs,
      outputs: outputs,
      double_satisfaction_prevented: True,
    )
  }

  else(_) {
    fail
  }
}
